CREATE TABLE IF NOT EXISTS Users (
    Id TEXT PRIMARY KEY,
    Email TEXT UNIQUE,
    PasswordHash TEXT,
    Name TEXT,
    CreatedAt TEXT,
    UpdatedAt TEXT
);

CREATE TABLE IF NOT EXISTS Tasks (
    Id TEXT PRIMARY KEY,
    Title TEXT,
    Description TEXT,
    Status TEXT,
    DueDate TEXT,
    UserId TEXT,
    CreatedAt TEXT,
    UpdatedAt TEXT,
    FOREIGN KEY(UserId) REFERENCES Users(Id)
);

